testbench:
`timescale 1ns/1ps
module tb;
  reg clk;
  reg reset;
  reg [7:0] in;
  wire [7:0] out;

  edge_capture8 dut(.clk(clk), .reset(reset), .in(in), .out(out));

  always #5 clk = ~clk;

  task step_check;
    input [7:0] expected;
    begin
      @(posedge clk);
      #1;
      if (out !== expected) begin
        $display("FAIL expected=%0b got=%0b", expected, out);
        $fatal(1);
      end
    end
  endtask

  initial begin
    clk = 0;
    reset = 1;
    in = 8'b00000000;
    step_check(8'b00000000);

    reset = 0;
    step_check(8'b00000000);

    in = 8'b00010001;
    step_check(8'b00010001);
    step_check(8'b00010001);

    in = 8'b00010000;
    step_check(8'b00010001);

    in = 8'b10010010;
    step_check(8'b10010011);

    reset = 1;
    step_check(8'b00000000);

    reset = 0;
    in = 8'b01000000;
    step_check(8'b01000000);

    $display("PASS");
    $finish;
  end
endmodule

reference_rtl:
module edge_capture8(input clk, input reset, input [7:0] in, output reg [7:0] out);
  reg [7:0] in_d;

  always @(posedge clk) begin
    if (reset) begin
      out <= 8'b00000000;
      in_d <= 8'b00000000;
    end else begin
      out <= out | (~in_d & in);
      in_d <= in;
    end
  end
endmodule
